// monitorC is where relationship counts are stored.
type monitorC struct {
	Heartbeats                *int64
	MonitorGroups             *int64
	MonitorMaintenances       *int64
	MonitorNotifications      *int64
	MonitorTags               *int64
	NotificationSentHistories *int64
	StatDailies               *int64
	StatHourlies              *int64
	StatMinutelies            *int64
}

// PreloadCount sets a count in the C struct by name
func (o *Monitor) PreloadCount(name string, count int64) error {
	if o == nil {
		return nil
	}

	switch name {
	case "Heartbeats":
		o.C.Heartbeats = &count
	case "MonitorGroups":
		o.C.MonitorGroups = &count
	case "MonitorMaintenances":
		o.C.MonitorMaintenances = &count
	case "MonitorNotifications":
		o.C.MonitorNotifications = &count
	case "MonitorTags":
		o.C.MonitorTags = &count
	case "NotificationSentHistories":
		o.C.NotificationSentHistories = &count
	case "StatDailies":
		o.C.StatDailies = &count
	case "StatHourlies":
		o.C.StatHourlies = &count
	case "StatMinutelies":
		o.C.StatMinutelies = &count
	}
	return nil
}

